25796     auto ZExtIt = UsedReductionOpIds.find(Instruction::ZExt);
25797     auto SelectIt = UsedReductionOpIds.find(Instruction::Select);
25798     if (ZExtIt != UsedReductionOpIds.end() &&
25799         SelectIt != UsedReductionOpIds.end()) {
25800       unsigned ZExtIdx = ZExtIt->second;
25801       unsigned SelectIdx = SelectIt->second;
25802       auto *ZExt = cast<ZExtInst>(ReducedVals[ZExtIdx].front());
25803       // ZExt is compatible with Select? Merge select to zext, if so.
25804       if (ZExt->getSrcTy()->isIntegerTy(1) &&
25805           ZExt->getType() == ReducedVals[SelectIdx].front()->getType()) {
25806         ReducedVals[ZExtIdx].append(ReducedVals[SelectIdx]);
25807         ReducedVals.erase(std::next(ReducedVals.begin(), SelectIdx));
25808       }
25809     }
25810     // Check if shl %x, 1 can be merged with adds.
25811     auto ShlIt = UsedReductionOpIds.find(Instruction::Shl);
25812     auto AddIt = UsedReductionOpIds.find(Instruction::Add);
25813     if (ShlIt != UsedReductionOpIds.end() &&
25814         AddIt != UsedReductionOpIds.end()) {
25815       unsigned ShlIdx = ShlIt->second;
25816       unsigned AddIdx = AddIt->second;
25817       if (ReducedVals[ShlIdx].size() < ReductionLimit) {
25818         SmallVector<Value *> Shls;
25819         SmallVector<Value *> Remaining;
25820         for (Value *V : ReducedVals[ShlIdx]) {
25821           if (match(V, m_Shl(m_Value(), m_One())))
25822             Shls.push_back(V);
25823           else
25824             Remaining.push_back(V);
25825         }
25826         // Have compatible shls? Merge them to adds, if so.
25827         if (!Shls.empty()) {
25828           Shls.append(ReducedVals[AddIdx]);
25829           ReducedVals[AddIdx].swap(Shls);
